// Extraer datos del webhook de Freshworks.
const body = $json.body || $json;
const action = body.action || body.event || '';
const actor = body.actor || {};
const data = body.data || {};
const msg = data.message || body.message || {};
const parts = msg.message_parts || data.message_parts || [];
const conv = msg.conversation_id || data.conversation_id || body.conversation_id || '';

let userText = '';
let audioFileUrl = '';
let audioFileName = '';
let imageFileUrl = '';
let imageFileName = '';
let fileUrl = '';
let fileName = '';
let fileContentType = '';

function firstUrl(attachment) {
  if (!attachment) return '';
  return attachment.url || attachment.download_url || attachment.full_size_url || attachment.file_url || attachment.thumbnail_url || '';
}

for (const part of parts) {
  if (part.text?.content) userText += part.text.content + ' ';
  if (typeof part.text === 'string') userText += part.text + ' ';

  if (part.image) {
    userText += '[imagen] ';
    imageFileUrl = imageFileUrl || firstUrl(part.image);
    imageFileName = imageFileName || part.image.name || part.image.file_name || 'imagen';
  }

  if (part.audio) {
    userText += '[audio] ';
    audioFileUrl = audioFileUrl || firstUrl(part.audio);
    audioFileName = audioFileName || part.audio.name || part.audio.file_name || 'audio.ogg';
  }

  if (part.file) {
    const ct = (part.file.content_type || part.file.mime_type || '').toLowerCase();
    const isAudioFile = ct.startsWith('audio/') || ['ogg','mpeg','mp4','m4a','wav','webm','aac','flac'].some(e => ct.includes(e));
    if (isAudioFile) {
      userText += '[audio] ';
      audioFileUrl = audioFileUrl || firstUrl(part.file);
      audioFileName = audioFileName || part.file.name || part.file.file_name || 'audio.ogg';
    } else {
      userText += '[archivo] ';
      fileUrl = fileUrl || firstUrl(part.file);
      fileName = fileName || part.file.name || part.file.file_name || 'archivo';
      fileContentType = fileContentType || ct;
    }
  }
}

if (!userText && msg.content) userText = String(msg.content);
if (!userText && data.content) userText = String(data.content);
if (!userText && body.content) userText = String(body.content);
userText = userText.trim();

const actorType = String(actor.actor_type || msg.actor_type || data.actor_type || '').toLowerCase();
const messageType = String(msg.message_type || data.message_type || '').toLowerCase();
const isOutgoingActor = ['agent', 'bot', 'admin', 'system'].includes(actorType);
const isPrivateOrSystem = ['private', 'system'].includes(messageType);
const isMessageCreate = !action || String(action).toLowerCase() === 'message_create';
const actorId = actor.actor_id || msg.actor_id || data.user_id || '';
const messageId = msg.id || msg.message_id || data.message_id || body.message_id || '';
const createdTime = msg.created_time || data.created_time || body.created_time || '';
const duplicateKey = messageId
  ? 'message:' + messageId
  : (createdTime && conv ? 'fallback:' + conv + ':' + (actorId || 'no-user') + ':' + createdTime : '');

const hasImage = Boolean(imageFileUrl || userText.includes('[imagen]'));
const hasFile = Boolean(fileUrl || userText.includes('[archivo]'));
const isUserMessage =
  isMessageCreate &&
  !isOutgoingActor &&
  !isPrivateOrSystem &&
  userText.length > 0;

return [{
  userText,
  sessionId: conv || actorId || 'anon_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6),
  conversationId: conv,
  userId: actorId,
  messageId,
  createdTime,
  duplicateKey,
  isUserMessage,
  rawAction: action,
  actorType,
  messageType,
  hasAudio: Boolean(audioFileUrl),
  audioFileUrl,
  audioFileName,
  hasImage,
  imageFileUrl,
  imageFileName,
  hasFile,
  fileUrl,
  fileName,
  fileContentType,
}];

const originalText = ($json.userText || '').trim();
const normalizedText = originalText
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/\s+/g, ' ')
  .toLowerCase()
  .trim();

const cleanText = normalizedText
  .replace(/\[(imagen|archivo|audio|audio no procesado)\]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const tokens = cleanText
  .split(/[^a-z0-9+]+/i)
  .map((token) => token.trim())
  .filter(Boolean);

const hasImage = Boolean($json.hasImage || originalText.includes('[imagen]'));
const hasFile = Boolean($json.hasFile || originalText.includes('[archivo]'));
const hasMedia = hasImage || hasFile;
const mediaKind = hasImage ? 'imagen' : (hasFile ? 'archivo' : 'texto');
const phoneMatch = originalText.match(/(?:\+?57\s?)?(3\d{2}[\s.-]?\d{3}[\s.-]?\d{4})/);
const phone = phoneMatch ? phoneMatch[0].replace(/[^+\d]/g, '') : '';

const namePatterns = [
  /(?:mi nombre es|me llamo|soy)\s+([A-Z\u00C0-\u017F][A-Za-z\u00C0-\u017F]+(?:\s+[A-Z\u00C0-\u017F][A-Za-z\u00C0-\u017F]+){0,3})/,
  /(?:nombre[:\s]+)([A-Z\u00C0-\u017F][A-Za-z\u00C0-\u017F]+(?:\s+[A-Z\u00C0-\u017F][A-Za-z\u00C0-\u017F]+){0,3})/,
];

let fullName = '';
for (const pattern of namePatterns) {
  const match = originalText.match(pattern);
  if (match?.[1]) {
    fullName = match[1].trim().replace(/[.,;:]+$/, '');
    break;
  }
}

function escapeRegExp(value) {
  return String(value || '').replace(/[-/\\^$*+?.()|[\]{}]/g, '\\$&');
}

function countHits(words) {
  return words.reduce((count, word) => {
    const normalized = String(word || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
    if (!normalized) return count;
    if (normalized.includes(' ')) return count + (cleanText.includes(normalized) ? 1 : 0);
    return count + (new RegExp('\\b' + escapeRegExp(normalized) + '\\b').test(cleanText) ? 1 : 0);
  }, 0);
}

const explicitEnglish =
  /\b(no spanish|no espanol|english|ingles|in english|speak english|can you speak english)\b/.test(cleanText) ||
  /no\s+(spanish|espanol).*(english|ingles)/.test(cleanText);
const explicitSpanish =
  !explicitEnglish &&
  (/\b(espanol|spanish|en espanol|habla espanol|speak spanish|no english|no ingles)\b/.test(cleanText) ||
  /no\s+(english|ingles).*(spanish|espanol)/.test(cleanText));

const englishHits = countHits([
  'hi', 'hello', 'hey', 'good morning', 'good afternoon', 'good evening', 'please', 'thanks',
  'price', 'cost', 'how much', 'appointment', 'book', 'schedule', 'reschedule', 'cancel',
  'location', 'address', 'where', 'service', 'treatment', 'advisor', 'dentist', 'doctor',
  'photo', 'picture', 'xray', 'x-ray', 'radiography', 'quote', 'estimate'
]);
const spanishHits = countHits([
  'hola', 'buenas', 'buenos dias', 'buenas tardes', 'buenas noches', 'por favor', 'gracias',
  'precio', 'valor', 'cuanto cuesta', 'cita', 'agendar', 'reprogramar', 'cancelar',
  'ubicacion', 'direccion', 'donde', 'servicio', 'tratamiento', 'asesor', 'odontologo', 'doctor',
  'foto', 'imagen', 'radiografia', 'cotizacion', 'presupuesto'
]);

let detectedLanguage = '';
if (englishHits > 0 && englishHits >= spanishHits) detectedLanguage = 'en';
else if (spanishHits > 0 && spanishHits > englishHits) detectedLanguage = 'es';

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversationState) staticData.conversationState = {};
const stateKey = $json.sessionId || $json.conversationId || $json.userId || 'unknown';
const state = staticData.conversationState[stateKey] || {};
const explicitLanguage = explicitEnglish ? 'en' : (explicitSpanish ? 'es' : '');

if (explicitLanguage) state.languagePreference = explicitLanguage;
if (detectedLanguage) state.lastDetectedLanguage = detectedLanguage;
state.updatedAt = new Date().toISOString();
staticData.conversationState[stateKey] = state;

const responseLanguage = explicitLanguage || state.languagePreference || detectedLanguage || state.lastDetectedLanguage || 'es';
const languageSource = explicitLanguage
  ? 'explicit'
  : (state.languagePreference ? 'preference' : (detectedLanguage ? 'detected' : (state.lastDetectedLanguage ? 'last_detected' : 'default')));

return [{
  ...$json,
  originalText,
  normalizedText,
  cleanText,
  tokens,
  contactInfo: {
    fullName,
    phone,
    hasName: Boolean(fullName),
    hasPhone: Boolean(phone),
  },
  language: {
    response: responseLanguage,
    detected: detectedLanguage,
    explicit: explicitLanguage,
    preference: state.languagePreference || '',
    lastDetected: state.lastDetectedLanguage || '',
    source: languageSource,
  },
  conversationState: state,
  messageMeta: {
    length: originalText.length,
    tokenCount: tokens.length,
    hasImage,
    hasFile,
    hasMedia,
    mediaKind,
    imageFileUrl: $json.imageFileUrl || '',
    imageFileName: $json.imageFileName || '',
    fileUrl: $json.fileUrl || '',
    fileName: $json.fileName || '',
    fileContentType: $json.fileContentType || '',
    normalizedAt: new Date().toISOString(),
  },
}];

const text = $json.cleanText || $json.normalizedText || '';
const includesAny = (words) => words.some((word) => text.includes(
  String(word || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
));

function escapeRegExp(value) {
  return String(value || '').replace(/[-/\\^$*+?.()|[\]{}]/g, '\\$&');
}

function detectAppointmentAction() {
  if (includesAny(['cancelar cita', 'cancela mi cita', 'anular cita', 'eliminar cita', 'no puedo asistir', 'cancel appointment', 'cancel my appointment'])) return 'cancelar';
  if (includesAny(['reprogramar', 'cambiar cita', 'mover cita', 'aplazar', 'posponer', 'cambiar la hora', 'cambiar fecha', 'reschedule', 'change appointment'])) return 'reprogramar';
  if (includesAny(['consultar cita', 'tengo cita', 'mi cita', 'cuando es mi cita', 'confirmar cita', 'ver mi cita', 'confirm appointment', 'check appointment'])) return 'consultar';
  if (includesAny(['agendar', 'agenda', 'sacar cita', 'quiero cita', 'necesito cita', 'reservar', 'programar cita', 'separar cita', 'turno', 'disponibilidad', 'hora disponible', 'appointment', 'book', 'schedule', 'availability'])) return 'agendar';
  return 'none';
}

function detectClinicalService() {
  const services = [
    { id: 'armonizacion_facial', words: ['armonizacion facial', 'armonizacion', 'mandibula', 'menton', 'labios', 'pomulos', 'perfil facial', 'acido hialuronico', 'facial harmonization', 'facial balancing', 'jawline', 'chin', 'lips', 'cheeks'] },
    { id: 'lifting', words: ['lifting', 'lifting facial', 'ritidoplastia', 'flacidez', 'papada', 'rejuvenecimiento facial', 'facelift', 'face lift', 'sagging skin'] },
    { id: 'ortodoncia', words: ['ortodoncia', 'brackets', 'alineadores', 'alineador', 'invisalign', 'orthodontics', 'braces', 'aligners'] },
    { id: 'implantes', words: ['implante', 'implantes', 'implantologia', 'diente perdido', 'molar perdido', 'dental implant', 'dental implants', 'missing tooth', 'missing teeth'] },
    { id: 'diseno_sonrisa', words: ['diseno de sonrisa', 'resinas esteticas', 'carillas', 'blanqueamiento', 'sonrisa', 'smile makeover', 'smile design', 'veneers', 'whitening', 'teeth whitening'] },
    { id: 'endodoncia', words: ['endodoncia', 'conducto', 'tratamiento de conducto', 'nervio dental', 'dolor dental', 'root canal', 'tooth nerve', 'tooth pain'] },
    { id: 'periodoncia', words: ['periodoncia', 'encias', 'encia', 'sangrado al cepillar', 'periodontitis', 'gingivitis', 'movilidad dental', 'periodontics', 'gums', 'bleeding gums', 'gum disease'] },
    { id: 'maxilofacial', words: ['maxilofacial', 'cirugia maxilofacial', 'cordales', 'fracturas faciales', 'mandibulares', 'extraccion de cordales', 'maxillofacial', 'wisdom teeth', 'wisdom tooth', 'jaw surgery'] },
    { id: 'rehabilitacion_oral', words: ['rehabilitacion oral', 'dientes desgastados', 'dientes fracturados', 'perdida dental', 'masticar', 'oral rehabilitation', 'worn teeth', 'fractured teeth'] },
    { id: 'estetica_dental', words: ['estetica dental', 'blanqueamiento dental', 'cosmetic dentistry', 'dental aesthetics'] },
    { id: 'cirugia_oral', words: ['cirugia oral', 'muela del juicio', 'extraccion', 'oral surgery', 'tooth extraction'] },
    { id: 'limpieza_revision', words: ['limpieza', 'profilaxis', 'revision dental', 'control dental', 'dental cleaning', 'checkup'] },
    { id: 'urgencia', words: ['urgencia', 'dolor', 'sangrado', 'inflamacion', 'infeccion', 'emergency'] },
  ];

  const matchesService = (words) => words.some(word => {
    const normalized = String(word || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
    if (!normalized.includes(' ')) {
      return new RegExp('\\b' + escapeRegExp(normalized) + '\\b').test(text);
    }
    return text.includes(normalized);
  });

  return services.find((service) => matchesService(service.words))?.id || 'desconocido';
}

function detectGeneralTopic() {
  if (includesAny(['ubicacion', 'ubicados', 'ubicado', 'direccion', 'donde estan', 'donde quedan', 'donde queda', 'sede', 'como llegar', 'maps', 'pereira', 'location', 'address', 'where are you', 'where are you located', 'how to get there'])) return 'ubicacion';
  if (includesAny(['horario', 'hora atienden', 'atienden', 'abren', 'cierran', 'sabado', 'domingo', 'festivo', 'hours', 'opening hours', 'business hours', 'open', 'close'])) return 'horario';
  if (includesAny(['telefono', 'whatsapp', 'numero', 'contacto', 'llamar', 'celular', 'phone', 'contact', 'call', 'number'])) return 'contacto';
  if (includesAny(['servicios', 'tratamientos', 'especialidades', 'que hacen', 'que ofrecen', 'services', 'treatments', 'specialties'])) return 'servicios';
  if (includesAny(['pago', 'pagos', 'tarjeta', 'transferencia', 'efectivo', 'financiacion', 'credito', 'payment', 'payments', 'card', 'cash', 'financing', 'credit'])) return 'pagos';
  return '';
}

const appointmentAction = detectAppointmentAction();
const clinicalService = detectClinicalService();
const generalTopic = detectGeneralTopic();
const isGreeting = /^(hola|buenas|buenos dias|buenas tardes|buenas noches|hello|hi|hey|ola)\b/.test(text);
const asksPrice = includesAny(['precio', 'valor', 'cuanto cuesta', 'costo', 'vale', 'tarifa', 'cotizacion', 'presupuesto', 'price', 'cost', 'how much', 'quote', 'estimate', 'budget']);
const asksInfo = Boolean(generalTopic) || includesAny(['informacion', 'info', 'que es', 'como funciona', 'cuentame', 'me interesa', 'quiero saber', 'explicame', 'donde', 'cuando', 'cual', 'cuales', 'information', 'what is', 'how does it work', 'tell me', 'interested', 'where', 'when', 'which']);
const asksAvailability = includesAny(['disponibilidad', 'hay cupo', 'hay cita', 'hoy', 'manana', 'esta semana', 'lo antes posible', 'urgente', 'availability', 'available', 'today', 'tomorrow', 'this week', 'as soon as possible', 'urgent']);

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversationState) staticData.conversationState = {};
const stateKey = $json.sessionId || $json.conversationId || $json.userId || 'unknown';
const state = staticData.conversationState[stateKey] || $json.conversationState || {};
const rememberedService = state.lastService || '';
const canUseRememberedService =
  clinicalService === 'desconocido' &&
  rememberedService &&
  !generalTopic &&
  (asksPrice || asksInfo || appointmentAction !== 'none' || Boolean($json.messageMeta?.hasMedia));

const requestedService = clinicalService !== 'desconocido'
  ? clinicalService
  : (canUseRememberedService ? rememberedService : (generalTopic ? 'general' : 'desconocido'));
const serviceResolvedFromMemory = Boolean(canUseRememberedService);

let primaryIntent = 'desconocida';
if (appointmentAction !== 'none') primaryIntent = 'gestion_cita';
else if (asksPrice) primaryIntent = 'precio';
else if (asksInfo || requestedService !== 'desconocido') primaryIntent = 'informacion';
else if (isGreeting) primaryIntent = 'saludo';

if (clinicalService !== 'desconocido' && clinicalService !== 'general' && clinicalService !== 'urgencia') {
  state.lastService = clinicalService;
}
if (primaryIntent !== 'desconocida') state.lastIntent = primaryIntent;
state.lastUserText = $json.originalText || $json.userText || '';
state.updatedAt = new Date().toISOString();
staticData.conversationState[stateKey] = state;

const leadSignals = [];
let leadScore = 0;
if (appointmentAction !== 'none') { leadScore += 40; leadSignals.push('gestion_cita'); }
if (asksPrice) { leadScore += 25; leadSignals.push('pregunta_precio'); }
if (requestedService !== 'desconocido') { leadScore += 20; leadSignals.push(serviceResolvedFromMemory ? 'servicio_recordado' : 'servicio_identificado'); }
if (generalTopic) { leadScore += 10; leadSignals.push('general_' + generalTopic); }
if (asksAvailability) { leadScore += 15; leadSignals.push('busca_disponibilidad'); }
if ($json.contactInfo?.hasPhone) { leadScore += 10; leadSignals.push('telefono_detectado'); }
if ($json.contactInfo?.hasName) { leadScore += 5; leadSignals.push('nombre_detectado'); }

const normalizedLeadScore = Math.min(100, leadScore);
const leadTemperature = normalizedLeadScore >= 70 ? 'caliente' : normalizedLeadScore >= 40 ? 'tibio' : 'frio';

return [{
  ...$json,
  intent: {
    primary: primaryIntent,
    appointmentAction,
    asksPrice,
    asksInfo,
    asksAvailability,
    isGreeting,
    generalTopic,
  },
  appointmentIntent: appointmentAction,
  requestedService,
  effectiveService: requestedService,
  serviceResolvedFromMemory,
  conversationState: state,
  leadScore: normalizedLeadScore,
  leadSignals,
  leadTemperature,
  isHotLead: leadTemperature === 'caliente',
}];

const text = $json.normalizedText || '';
const includesAny = (words) => words.some((word) => text.includes(word));

const humanRequested = /(hablar con .*(doctor|doctora|medico|medica|asesor|asesora|humano|persona|alguien|agente)|necesito.*(doctor|doctora|medico|medica|asesor|asesora)|quiero.*hablar.*con|comunic.*(doctor|doctora|medico|asesor|asesora)|atencion.*humana|me atiende.*persona|pasame.*(asesor|humano)|necesito.*medico|quiero.*medico)/i.test(text);

const clinicalRisk = includesAny([
  'dolor fuerte',
  'dolor insoportable',
  'dolor agudo',
  'mucho dolor',
  'me duele mucho',
  'me duele horrible',
  'dolor intenso',
  'sangrado',
  'hemorragia',
  'fiebre',
  'infeccion',
  'pus',
  'inflamacion fuerte',
  'muy inflamado',
  'no puedo respirar',
  'urgencia',
  'emergencia',
  'complicacion',
  'no puedo comer',
  'no puedo dormir del dolor',
]);

const softPainRisk = includesAny([
  'me duele',
  'tengo dolor',
  'dolor de muela',
  'dolor de diente',
  'dolor en la boca',
  'me esta doliendo',
  'me duelen',
]);

const commercialRisk = includesAny([
  'reclamo',
  'queja',
  'garantia',
  'devolucion',
  'demanda',
  'abogado',
  'mala praxis',
  'me fue mal',
]);

const sensitiveRequest = includesAny([
  'diagnostico',
  'recetame',
  'medicamento',
  'antibiotico',
  'anestesia',
  'embarazada',
  'menor de edad',
]);

const riskReasons = [];
if (humanRequested) riskReasons.push('solicitud_humano');
if (clinicalRisk) riskReasons.push('riesgo_clinico');
if (softPainRisk) riskReasons.push('dolor_leve');
if (commercialRisk) riskReasons.push('riesgo_comercial');
if (sensitiveRequest) riskReasons.push('consulta_sensible');

const riskLevel = clinicalRisk || commercialRisk || sensitiveRequest ? 'alto' : (humanRequested || softPainRisk ? 'medio' : 'bajo');

return [{
  ...$json,
  humanRequested,
  softPainRisk,
  risk: {
    level: riskLevel,
    clinicalRisk,
    softPainRisk,
    commercialRisk,
    sensitiveRequest,
    reasons: riskReasons,
  },
  highRisk: riskLevel === 'alto',
  mediumRisk: riskLevel === 'medio',
}];

const sourceItem = $items('Detectar riesgo/humano', 0, 0)[0]?.json || $input.all()[0]?.json || {};
const text = sourceItem.normalizedText || '';
const service = sourceItem.effectiveService || sourceItem.requestedService || 'desconocido';
const intent = sourceItem.intent || {};

function normalize(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

const includesAny = (words) => words.some((word) => text.includes(normalize(word)));
const hitCount = (words) => words.reduce((count, word) => count + (text.includes(normalize(word)) ? 1 : 0), 0);

const internalKnowledge = [
  {
    id: 'menu-general',
    service: 'general',
    intents: ['saludo'],
    anchors: ['hola', 'buenas', 'buenos dias', 'buenas tardes', 'buenas noches'],
    text: 'CiruNova puede orientar sobre citas, cirugias, asesorias y paso a asesor humano.',
  },
  {
    id: 'general-servicios',
    service: 'general',
    intents: ['informacion'],
    anchors: ['servicios', 'tratamientos', 'especialidades', 'que hacen', 'que ofrecen'],
    text: 'Servicios disponibles: odontologia general, cirugias orales y maxilofaciales, ortodoncia, diseno de sonrisa, implantes dentales, endodoncia, periodoncia, rehabilitacion oral, lifting facial, armonizacion facial.',
  },
  {
    id: 'general-horario',
    service: 'general',
    intents: ['informacion'],
    anchors: ['horario', 'atienden', 'abren', 'cierran', 'sabado', 'domingo', 'festivo'],
    text: 'Horario: lunes a viernes 8:00am-6:00pm, sabados 8:00am-12:00pm.',
  },
  {
    id: 'general-ubicacion',
    service: 'general',
    intents: ['informacion'],
    anchors: ['ubicacion', 'ubicado', 'ubicados', 'direccion', 'donde estan', 'donde quedan', 'donde queda', 'sede', 'como llegar', 'maps', 'pereira'],
    text: 'Direccion: Calle 14 #25-39, Pereira, Colombia.',
  },
  {
    id: 'general-contacto',
    service: 'general',
    intents: ['informacion'],
    anchors: ['telefono', 'whatsapp', 'numero', 'contacto', 'llamar', 'celular'],
    text: 'Telefono Cirumax: +57 315 8888120. WhatsApp CRM: +57 314 3066978.',
  },
  {
    id: 'agenda-general',
    service: 'general',
    intents: ['gestion_cita'],
    anchors: ['cita', 'agenda', 'agendar', 'reservar', 'disponibilidad', 'consultar cita', 'reprogramar', 'cancelar'],
    text: 'Datos para cita: nombre completo, telefono o documento, servicio, fecha preferida, franja horaria.',
  },
  {
    id: 'lifting-info',
    service: 'lifting',
    intents: ['informacion'],
    anchors: ['lifting', 'ritidoplastia', 'flacidez', 'rostro', 'facial', 'papada', 'rejuvenecimiento'],
    text: 'Lifting facial: mejora flacidez, definicion y armonia del rostro. Resultado natural. Preguntar que quiere mejorar.',
  },
  {
    id: 'lifting-precio',
    service: 'lifting',
    intents: ['precio'],
    anchors: ['lifting', 'facial', 'precio', 'valor', 'costo', 'cuanto cuesta', 'cotizacion', 'presupuesto'],
    text: 'Precio lifting: depende de flacidez, zonas, resultado deseado. Requiere valoracion presencial. Ofrecer agendar.',
  },
  {
    id: 'lifting-recuperacion',
    service: 'lifting',
    intents: ['informacion'],
    anchors: ['lifting', 'recuperacion', 'incapacidad', 'postoperatorio', 'reposo', 'cuidados'],
    text: 'Recuperacion lifting: depende del procedimiento y paciente. Valoracion explica tiempos y cuidados.',
  },
  {
    id: 'ortodoncia-info',
    service: 'ortodoncia',
    intents: ['informacion', 'precio'],
    anchors: ['ortodoncia', 'brackets', 'alineadores', 'invisalign', 'precio', 'valor'],
    text: 'Ortodoncia: valoracion revisa mordida, alineacion, objetivos. Opciones: brackets o alineadores. Precio segun caso.',
  },
  {
    id: 'implantes-info',
    service: 'implantes',
    intents: ['informacion', 'precio'],
    anchors: ['implante', 'implantes', 'implantologia', 'diente perdido', 'molar perdido', 'precio', 'valor'],
    text: 'Implantes: requiere valoracion de hueso, salud oral, zona. Presupuesto segun caso clinico.',
  },
  {
    id: 'estetica-info',
    service: 'estetica_dental',
    intents: ['informacion', 'precio'],
    anchors: ['estetica dental', 'diseno de sonrisa', 'blanqueamiento', 'carillas', 'sonrisa', 'precio', 'valor'],
    text: 'Estetica dental: se evalua sonrisa, color, forma, encia, expectativas. Recomendacion depende de valoracion.',
  },
  {
    id: 'cirugia-info',
    service: 'cirugia_oral',
    intents: ['informacion', 'precio'],
    anchors: ['cirugia', 'maxilofacial', 'cordales', 'muela del juicio', 'extraccion', 'precio', 'valor'],
    text: 'Cirugia oral/maxilofacial: requiere valoracion, imagenes diagnosticas si aplican, revision de complejidad.',
  },
  {
    id: 'urgencia-handoff',
    service: 'urgencia',
    intents: ['informacion'],
    anchors: ['urgencia', 'dolor', 'sangrado', 'inflamacion', 'infeccion'],
    text: 'Urgencia: dolor fuerte, sangrado, infeccion, fiebre → conectar con asesor/profesional.',
  },
];

function parseList(value) {
  return String(value || '')
    .split(/[|,;]/)
    .map((item) => normalize(item))
    .filter(Boolean);
}

function isActive(value) {
  return !['false', 'falso', 'no', '0', 'inactive', 'inactivo'].includes(normalize(value));
}

const sheetRows = $input.all()
  .map((item) => item.json || {})
  .filter((row) => !row.error && isActive(row.active ?? true) && row.text);

const sheetKnowledge = sheetRows.map((row, index) => ({
  id: row.id || 'sheet-' + (index + 1),
  service: normalize(row.service || 'general'),
  intents: parseList(row.intents || row.intent || 'informacion'),
  anchors: parseList(row.anchors || row.keywords || row.palabras_clave || ''),
  text: String(row.text || row.respuesta || '').trim(),
  source: 'sheet',
}));

const approvedKnowledge = sheetKnowledge.length > 0 ? sheetKnowledge : internalKnowledge.map((item) => ({ ...item, source: 'internal' }));

function scoreKnowledge(item) {
  if (item.service !== 'general' && service !== item.service) return 0;

  if (item.service === 'general') {
    const allowGeneral = service === 'general' || ['saludo', 'gestion_cita', 'informacion', 'precio'].includes(intent.primary);
    if (!allowGeneral) return 0;
  }

  let score = hitCount(item.anchors);
  if (item.intents.includes(intent.primary)) score += 2;
  if (item.service !== 'general' && service === item.service) score += 2;
  if (item.service === 'general' && service === 'general') score += 2;
  if (intent.generalTopic && item.id.includes(intent.generalTopic)) score += 4;
  if (intent.asksPrice && item.intents.includes('precio')) score += 1;
  if (intent.primary === 'saludo' && item.id === 'menu-general') score += 4;
  if (intent.primary === 'gestion_cita' && item.id === 'agenda-general') score += 4;
  return score;
}

const candidates = approvedKnowledge
  .map((item) => ({ ...item, score: scoreKnowledge(item) }))
  .filter((item) => item.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 3);

const topScore = candidates[0]?.score || 0;
const confidenceScore = Math.min(1, topScore / 6);
const confidenceLevel = confidenceScore >= 0.7 ? 'alta' : confidenceScore >= 0.5 ? 'media' : 'baja';

return [{
  json: {
    ...sourceItem,
    approvedKnowledgeVersion: sheetKnowledge.length > 0 ? 'sheet.Conocimiento' : 'internal.2026-05-16.v5',
    knowledgeSource: sheetKnowledge.length > 0 ? 'sheet' : 'internal',
    knowledgeRowsLoaded: sheetKnowledge.length,
    knowledgeCandidates: candidates,
    knowledgeConfidence: {
      score: confidenceScore,
      level: confidenceLevel,
      found: candidates.length > 0,
    },
  },
}];

const intent = $json.intent || {};
const risk = $json.risk || {};
const knowledge = $json.knowledgeConfidence || { found: false, level: 'baja', score: 0 };
const hasImage = Boolean($json.messageMeta?.hasImage);
const hasFile = Boolean($json.messageMeta?.hasFile);

let action = 'handoff_humano';
let reason = 'sin_conocimiento_suficiente';
let missingFields = [];

if ($json.humanRequested) {
  action = 'handoff_humano';
  reason = 'solicitud_humano';
} else if ($json.highRisk) {
  action = 'handoff_humano';
  reason = (risk.reasons || []).join(',') || 'riesgo_alto';
} else if ($json.requestedService === 'urgencia' || $json.softPainRisk) {
  action = 'handoff_humano';
  reason = 'urgencia_o_dolor_detectado';
} else if ($json.audioTranscriptionFailed) {
  action = 'handoff_humano';
  reason = 'audio_no_procesado';
} else if (hasImage || hasFile) {
  action = 'handoff_humano';
  reason = hasImage ? 'imagen_recibida' : 'archivo_recibido';
} else if (intent.appointmentAction && intent.appointmentAction !== 'none') {
  action = 'dentalink';
  reason = 'gestion_cita_transaccional';
} else if (intent.isGreeting) {
  action = 'responder_info';
  reason = 'saludo';
} else if (knowledge.found && knowledge.score >= 0.5) {
  action = 'responder_info';
  reason = 'conocimiento_aprobado';
} else if (intent.primary === 'desconocida' || !knowledge.found) {
  action = 'pedir_dato_faltante';
  reason = 'necesita_aclaracion';
  missingFields = ['servicio o necesidad principal'];
}

const advisorAlert =
  action === 'handoff_humano' ||
  $json.isHotLead ||
  ($json.intent?.asksPrice && $json.intent?.asksAvailability);

return [{
  ...$json,
  missingFields,
  decision: {
    action,
    reason,
    shouldUseAI: action === 'responder_info',
    shouldRegister: true,
    shouldNotifyAdvisor: advisorAlert,
    confidence: knowledge.level,
    leadScore: $json.leadScore || 0,
    leadTemperature: $json.leadTemperature || 'frio',
    leadSignals: $json.leadSignals || [],
  },
}];

const missing = $json.missingFields || ['servicio o necesidad principal'];
const lang = $json.language?.response || 'es';
const isEnglish = lang === 'en';
const explicitEnglish = $json.language?.explicit === 'en';

const fieldLabelsEn = {
  'servicio o necesidad principal': 'main service or need',
  'nombre completo': 'full name',
  'telefono': 'phone number',
  'servicio': 'service',
  'fecha preferida': 'preferred date',
  'franja horaria': 'preferred time range',
  'telefono o documento del paciente': 'patient phone number or ID',
  'cita actual': 'current appointment',
  'nueva fecha preferida': 'new preferred date',
  'nueva franja horaria': 'new preferred time range',
  'cita a cancelar': 'appointment to cancel',
};
const label = (field) => isEnglish ? (fieldLabelsEn[field] || field) : field;

let output = isEnglish
  ? 'Sure, I can help you with an appointment, treatment information, an estimate, or connecting you with an advisor. What do you need?'
  : 'Claro, para ayudarte mejor cuentame que necesitas: cita, informacion de un procedimiento, precio aproximado o hablar con un asesor.';

if (explicitEnglish && missing[0] === 'servicio o necesidad principal') {
  output = 'Of course, I can help you in English. Do you need an appointment, treatment information, an estimate, or an advisor?';
} else if (missing.length && missing[0] !== 'servicio o necesidad principal') {
  output = isEnglish
    ? 'To move forward I need: ' + missing.map(label).join(', ') + '.'
    : 'Claro, para avanzar necesito: ' + missing.join(', ') + '.';
}

return [{
  ...$json,
  output,
}];

const reason = $json.decision?.reason || ($json.risk?.reasons || []).join(',') || 'handoff';
const lang = $json.language?.response || 'es';
const isEnglish = lang === 'en';

const outputByReasonEs = {
  audio_no_procesado: 'Recibi tu nota de voz pero tuve un problema al procesarla. Te conecto con un asesor para que te atienda.',
  imagen_recibida: 'Recibi la imagen que mandaste. La paso a un asesor/profesional para que la revise; por seguridad no hago diagnosticos por chat.',
  archivo_recibido: 'Recibi el archivo que mandaste. Lo paso a un asesor para que lo revise y te ayude.',
  imagen_o_archivo_recibido: 'Recibi lo que mandaste. Se lo paso a un asesor para que lo revise y te ayude.',
  urgencia_o_dolor_detectado: 'Entiendo que tienes una molestia. Te conecto enseguida con un asesor.',
  solicitud_humano: 'Claro, te conecto con un asesor ahora.',
};

const outputByReasonEn = {
  audio_no_procesado: 'I received your voice note, but had trouble processing it. I will connect you with an advisor.',
  imagen_recibida: 'I received the image you sent. I will pass it to an advisor/professional to review; for safety I do not make diagnoses by chat.',
  archivo_recibido: 'I received the file you sent. I will pass it to an advisor so they can review it and help you.',
  imagen_o_archivo_recibido: 'I received what you sent. I will pass it to an advisor so they can review it and help you.',
  urgencia_o_dolor_detectado: 'I understand you are having discomfort. I will connect you with an advisor right away.',
  solicitud_humano: 'Sure, I will connect you with an advisor now.',
};

const outputByReason = isEnglish ? outputByReasonEn : outputByReasonEs;
const output = outputByReason[reason] || (isEnglish
  ? 'Sure, I will connect you with an advisor so they can help you personally.'
  : 'Claro, te conecto con un asesor para que te ayude personalmente.');

return [{
  ...$json,
  handoff: {
    required: true,
    reason,
    suggestedFreshworksActions: [
      'asignar_conversacion',
      'agregar_tag_requiere_humano',
      'crear_nota_interna_con_resumen',
    ],
  },
  output,
}];

const intent = $json.appointmentIntent || $json.intent?.appointmentAction || 'consultar';

const dentalinkRoutes = {
  agendar: { method: 'POST', path: '/appointments' },
  consultar: { method: 'GET', path: '/appointments' },
  reprogramar: { method: 'PATCH', path: '/appointments/{appointment_id}' },
  cancelar: { method: 'DELETE', path: '/appointments/{appointment_id}' },
};

const route = dentalinkRoutes[intent] || dentalinkRoutes.consultar;
const text = $json.originalText || $json.userText || '';
const phoneMatch = text.match(/(?:\+?57\s?)?(3\d{2}[\s.-]?\d{3}[\s.-]?\d{4})/);
const phone = $json.contactInfo?.phone || (phoneMatch ? phoneMatch[0].replace(/[^+\d]/g, '') : null);
const fullName = $json.contactInfo?.fullName || null;

const missingByIntent = {
  agendar: ['nombre completo', 'telefono', 'servicio', 'fecha preferida', 'franja horaria'],
