  service: $json.requestedService !== 'desconocido' ? $json.requestedService : null,
};

let missingFields = [...(missingByIntent[intent] || [])];
if (detected.fullName) missingFields = missingFields.filter((field) => field !== 'nombre completo');
if (detected.phone) missingFields = missingFields.filter((field) => !field.includes('telefono'));
if (detected.service) missingFields = missingFields.filter((field) => field !== 'servicio');

const payload = {
  patient: {
    full_name: detected.fullName,
    phone: detected.phone,
    document: null,
  },
  appointment: {
    service: detected.service,
    starts_at: null,
    ends_at: null,
    notes: text,
