// Deduplicación con staticData (persiste entre ejecuciones en n8n)
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenKeys) staticData.seenKeys = {};

const key = $json.duplicateKey || '';
const now = Date.now();

// Limpiar keys más viejas de 10 minutos para no crecer sin límite
const TEN_MINUTES = 10 * 60 * 1000;
for (const k of Object.keys(staticData.seenKeys)) {
  if (now - staticData.seenKeys[k] > TEN_MINUTES) {
    delete staticData.seenKeys[k];
  }
}

let isDuplicate = false;
if (key && staticData.seenKeys[key]) {
  isDuplicate = true;
}

if (key && !isDuplicate) {
  staticData.seenKeys[key] = now;
}

return [{
  ...$json,
  isDuplicate,
}];

const decision = $json.decision || {};
const risk = $json.risk || {};
const contact = $json.contactInfo || {};
const media = $json.messageMeta || {};
const shouldNotify =
  Boolean(decision.shouldNotifyAdvisor) ||
  Boolean($json.handoff?.required) ||
  $json.isHotLead === true;

const tag =
  $json.handoff?.required ? 'requiere_asesor' :
  $json.isHotLead ? 'lead_caliente' :
  risk.level === 'alto' ? 'riesgo_alto' :
  'seguimiento_bot';

const priority =
  risk.level === 'alto' ? 'Urgent' :
  $json.isHotLead ? 'High' :
  $json.leadTemperature === 'tibio' ? 'Medium' :
  'Low';

const summary = [
  'CiruNova: ' + tag,
  'Accion: ' + (decision.action || 'respuesta'),
  'Motivo: ' + (decision.reason || ''),
  'Idioma respuesta: ' + ($json.language?.response || 'es'),
  'Servicio: ' + ($json.requestedService || 'desconocido') + ($json.serviceResolvedFromMemory ? ' (recordado)' : ''),
  'Lead: ' + ($json.leadTemperature || 'frio') + ' (' + ($json.leadScore || 0) + ')',
  'Senales: ' + (($json.leadSignals || []).join(', ') || 'ninguna'),
  media.hasMedia ? 'Medio recibido: ' + (media.mediaKind || 'archivo') : null,
  media.imageFileUrl ? 'Imagen URL: ' + media.imageFileUrl : null,
  media.fileUrl ? 'Archivo URL: ' + media.fileUrl : null,
  contact.fullName ? 'Nombre: ' + contact.fullName : null,
  contact.phone ? 'Telefono: ' + contact.phone : null,
  'Mensaje: ' + ($json.originalText || $json.userText || ''),
].filter(Boolean).join('\n');

return [{
  ...$json,
  freshworksAdvisor: {
    shouldNotify,
    tag,
    priority,
    privateNote: summary,
  },
}];

